import{_ as r,C as s,o,c as l,a2 as e,E as i}from"./chunks/framework.BKG_UbFK.js";const g=JSON.parse('{"title":"仪表板","description":"","frontmatter":{},"headers":[],"relativePath":"zh/features/dashboard.md","filePath":"zh/features/dashboard.md"}'),n={name:"zh/features/dashboard.md"};function c(d,a,h,p,u,_){const t=s("Screenshot");return o(),l("div",null,[a[0]||(a[0]=e('<h1 id="仪表板" tabindex="-1">仪表板 <a class="header-anchor" href="#仪表板" aria-label="Permalink to &quot;仪表板&quot;">​</a></h1><p>仪表板是 Clearance 面板的落地页。它一目了然地展示了你应用的授权状态概览——无需任何配置。</p><h2 id="展示内容" tabindex="-1">展示内容 <a class="header-anchor" href="#展示内容" aria-label="Permalink to &quot;展示内容&quot;">​</a></h2><ul><li><strong>角色总数</strong>——所有 Spatie 角色的数量。</li><li><strong>看守器总数</strong>——由 Clearance 管理的所有看守器的数量（参见<a href="/clearance-docs/zh/features/guards.html">看守器</a>）。</li><li><strong>权限总数</strong>——所有 Spatie 权限的数量。</li><li><strong>权限组</strong>——不同权限组的数量，源自命名前缀（<code>group-action</code> 中的 <code>group</code>，例如 <code>orders-create</code> 中的 <code>orders</code>）。命名约定请参见<a href="/clearance-docs/zh/features/permissions.html">权限</a>。</li><li><strong>上下文角色分配</strong>——限定在特定模型实例（一个 Store、一个 Tenant、一个 Project）范围内的角色分配数量。参见<a href="/clearance-docs/zh/features/contextual-authorization.html">上下文授权</a>。</li><li><strong>按用户数排名前 5 的角色</strong>——分配用户数最多的五个角色，按排名列出。</li></ul>',4)),i(t,{src:"/screenshots/dashboard-page.png",alt:"Clearance 仪表板显示角色、看守器和权限数量",caption:"仪表板汇总了角色、看守器、权限、权限组、上下文分配以及排名靠前的角色。"}),a[1]||(a[1]=e('<h2 id="访问仪表板" tabindex="-1">访问仪表板 <a class="header-anchor" href="#访问仪表板" aria-label="Permalink to &quot;访问仪表板&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>路由名称</th><th>说明</th></tr></thead><tbody><tr><td><code>/clearance</code></td><td><code>clearance.home</code></td><td>仪表板</td></tr></tbody></table><p>阅读仪表板需要 <code>clearance-access</code> 权限，与其他任何面板分区相同。完整的访问控制表请参见<a href="/clearance-docs/zh/features/super-admin.html#面板访问与精细化的写权限">超级管理员</a>。</p><h2 id="嵌入组件" tabindex="-1">嵌入组件 <a class="header-anchor" href="#嵌入组件" aria-label="Permalink to &quot;嵌入组件&quot;">​</a></h2><p>仪表板是一个自包含的 Livewire 组件。可以将其挂载到你自己的布局中的任意位置——无论是替代还是补充预置的 <code>/clearance</code> 路由：</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::dashboard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/features/permissions.html">权限</a>——管理为仪表板计数提供数据的权限列表。</li><li><a href="/clearance-docs/zh/features/roles.html">角色</a>——管理“按用户数排名前 5”这一统计数据背后的角色。</li><li><a href="/clearance-docs/zh/features/contextual-authorization.html">上下文授权</a>——了解什么是上下文角色分配。</li></ul>',8))])}const m=r(n,[["render",c]]);export{g as __pageData,m as default};
